# Math utilities module

def add(a: int, b: int) -> int:
    return a + b

def multiply(a: int, b: int) -> int:
    return a * b

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

@static
PI: float = 3.14159

