# String utilities module

def greet(name: str) -> str:
    return f"Hello, {name}!"

def repeat(text: str, times: int) -> str:
    result: str = ""
    i: int = 0
    while i < times:
        result += text
        i += 1
    return result

def is_palindrome(s: str) -> bool:
    left: int = 0
    right: int = len(s) - 1
    while left < right:
        if str(s[left]) != str(s[right]):
            return False
        left += 1
        right -= 1
    return True
